 const handleEndGig = async () => {
  // Prevent multiple simultaneous calls
  if (isEndingGig) {
    console.log('⚠️ Already ending gig, ignoring duplicate call');
    return;
  }
  
  if (!window.confirm('End this gig?')) return;
  
