                        return ['live', 'checkVenue', 'upcoming'].includes(status);
                      }).length;
                      const totalActiveCount = nearbyGigs.filter(gig => {
                        const status = calculateGigStatus(gig);
                        return ['live', 'checkVenue', 'upcoming'].includes(status);
                      }).length;
                      return activeCount;
                    })()}
