                  // Separate gigs by status
                  const liveGigs = displayGigs.filter(g => g.calculatedStatus === 'live');
                  const upcomingGigs = displayGigs.filter(g => g.calculatedStatus === 'upcoming' || g.calculatedStatus === 'checkVenue');

                  return (
