                </button>
              </>
            ) : (
              <div className="space-y-4">
                <p className="text-white text-xl text-center mb-4">Choose your role:</p>
                
                <button
                  onClick={() => {
                    setAuthUserType('artist');
                    setShowAuthModal(true);
                  }}
