                  className="w-full px-8 py-4 bg-gradient-to-r from-blue-500 to-teal-500 hover:from-blue-600 hover:to-teal-600 text-white rounded-xl font-bold text-xl"
                >
                  👥 Audience Sign In
                </button>
              </div>
            )}
          </div>
        </div>
      </div>
    );
  }
  
// Artist Mode  
  if (mode === 'artist') {
    return (
      <div className="rock-background min-h-screen p-4 pb-24 md:pb-4">
        <div className="max-w-6xl mx-auto pt-6">
