                </h1>
                <p className="text-electric text-lg font-semibold">
                  Welcome, {currentUser?.displayName || currentUser?.email}
                </p>
              </div>
              <div className="flex gap-3">
                <button
                  onClick={() => setMode('discover')}
                  className="btn btn-ghost"
                >
                  ← Back
                </button>
                <button
                  onClick={async () => {
                    await signOutUser();
                    setMode('discover');
                  }}
                  className="btn btn-fire"
                >
                  Sign Out
                </button>
